import{_ as s,c as e,o,ah as a}from"./chunks/framework.RCw5T9E9.js";const h=JSON.parse('{"title":"Расширенный режим захвата (Advanced mode)","description":"","frontmatter":{"title":"Расширенный режим захвата (Advanced mode)"},"headers":[],"relativePath":"ru/network/advanced.md","filePath":"ru/network/advanced.md"}'),r={name:"ru/network/advanced.md"};function n(d,t,i,g,l,c){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="расширенныи-режим-захвата-advanced-mode" tabindex="-1">Расширенный режим захвата (Advanced mode) <a class="header-anchor" href="#расширенныи-режим-захвата-advanced-mode" aria-label="Permalink to &quot;Расширенный режим захвата (Advanced mode)&quot;">​</a></h1><p>В разделе <strong>Options → Network</strong> можно выбрать <strong>режим захвата</strong> сетевого обмена:</p><table tabindex="0"><thead><tr><th>Режим</th><th>В интерфейсе</th><th>Суть</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>«классический» снимок</td><td>Те же ограничения, что у перехвата на странице: видны заголовки и тело в объёме, доступном скрипту страницы (в т.ч. правила <strong>CORS</strong> для чужого origin). Подробнее см. <a href="./general.html#ограничения-отображения">Работа с запросами</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>расширенный захват</td><td>Расширение запрашивает доступ к <strong><code>webRequest</code></strong> и дополняет карточку запроса <strong>полным набором заголовков</strong> запроса и ответа так, как их видит браузер на уровне обмена, а не только «разрешённый странице» список.</td></tr></tbody></table><p>Включение <strong>Advanced mode</strong> и сопутствующие действия (закрепление заголовков, <strong>Header links</strong>, редактирование правил со <strong>Extract regex</strong> и <strong>Transform</strong>) доступны <strong>только в расширении</strong> для Chrome / Edge.<br><strong>В Standalone</strong> по-прежнему используется сценарий без расширенного захвата: полный набор заголовков через <strong><code>webRequest</code></strong>, описанный ниже, там <strong>недоступен</strong>.</p><hr><h2 id="что-дает-advanced-mode-во-вкладке-network" tabindex="-1">Что даёт Advanced mode во вкладке Network <a class="header-anchor" href="#что-дает-advanced-mode-во-вкладке-network" aria-label="Permalink to &quot;Что даёт Advanced mode во вкладке Network&quot;">​</a></h2><ul><li><strong>Заголовки запроса и ответа</strong> в детализации запроса отражают расширенные данные (в том числе служебные и не попавшие в <code>Access-Control-Expose-Headers</code>).</li><li><strong>Закрепление строк заголовков (pin)</strong> — для имени заголовка можно закрепить строку <strong>вверху списка</strong> отдельно для блока <strong>Request</strong> и отдельно для <strong>Response</strong>. Закрепления выполняются из <strong>меню строки</strong> заголовка (три точки) при активном Advanced mode.</li><li><strong>Header links</strong> — правило «для этого заголовка на этом хосте открыть внешний URL», в шаблоне подставляется подготовленное значение вместо плейсхолдера <code>{value}</code>.</li></ul><p>Управление списком правил <strong>Header links</strong> и таблицей <strong>Pinned headers</strong> в <strong>Options → Network</strong> показывается <strong>только при включённом Advanced mode</strong>, чтобы не загружать настройки в Classic mode.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Правило задаёт:</p><ul><li><strong>Header</strong> — имя HTTP-заголовка (сопоставление <strong>без учёта регистра</strong>);</li><li><strong>Host</strong> — хост URL запроса (нормализуется, без схемы и пути, например <code>api.example.com</code>);</li><li><strong>Link</strong> — шаблон URL, где фрагмент <strong><code>{value}</code></strong> заменяется на <strong>итоговую строку</strong> после этапов извлечения и преобразования (см. ниже).</li></ul><p>Создание и правка правил доступны из <strong>меню строки заголовка</strong> во вкладке <strong>Network</strong> (Advanced) и из <strong>Options</strong> при выбранной группе правил для заголовка.</p><p>Подстановка <strong><code>{value}</code></strong> выполняется так:</p><ol><li>Берётся <strong>сырое</strong> значение заголовка из карточки запроса.</li><li>Необязательно применяется <strong>Extract regex</strong> (если поле задано).</li><li>Необязательно применяется цепочка <strong>Transform</strong> (если поле задано).</li><li>Результат подставляется во все вхождения <strong><code>{value}</code></strong> в шаблоне ссылки.</li></ol><p>Поля <strong>Extract regex</strong> и <strong>Transform</strong> <strong>независимы</strong>: можно задать только regex, только transform или оба.</p><hr><h2 id="extract-regex" tabindex="-1">Extract regex <a class="header-anchor" href="#extract-regex" aria-label="Permalink to &quot;Extract regex&quot;">​</a></h2><ul><li>Строка трактуется как <strong>паттерн</strong> для конструктора <strong><code>new RegExp(pattern)</code></strong> (без отдельного аргумента с флагами; при необходимости флаги включаются в литерал регулярного выражения в самой строке, если синтаксис это допускает).</li><li>Выполняется <strong><code>String.prototype.match</code></strong> для <strong>сырого</strong> значения заголовка.</li><li>Если есть <strong>первая захватывающая группа</strong> и она участвует в совпадении, в дальнейшую обработку идёт <strong>она</strong>.</li><li>Если групп нет, используется <strong>всё совпадение</strong> целиком.</li><li>Если паттерн <strong>некорректен</strong> или <strong>совпадения нет</strong>, для следующего шага используется <strong>исходное</strong> значение заголовка (как до regex).</li></ul><h3 id="примеры-паттернов" tabindex="-1">Примеры паттернов <a class="header-anchor" href="#примеры-паттернов" aria-label="Permalink to &quot;Примеры паттернов&quot;">​</a></h3><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">([a-f0-9-]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">https</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\/\\/([</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">^</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\/]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><hr><h2 id="transform" tabindex="-1">Transform <a class="header-anchor" href="#transform" aria-label="Permalink to &quot;Transform&quot;">​</a></h2><p>Строка <strong>Transform</strong> описывает цепочку шагов, разделённых символом <strong><code>|</code></strong> (вертикальная черта). Шаги выполняются <strong>слева направо</strong>, каждый получает результат предыдущего.</p><p>Каждый шаг — вызов «функции» в скобках, по смыслу близко к подстановке в коде:</p><table tabindex="0"><thead><tr><th>Функция</th><th>Назначение</th><th>Пример</th></tr></thead><tbody><tr><td><strong><code>trim()</code></strong></td><td>Убрать пробелы в начале и конце</td><td><code>&quot; abc &quot;</code> → <code>&quot;abc&quot;</code></td></tr><tr><td><strong><code>lowercase()</code></strong></td><td>Нижний регистр</td><td><code>ABC</code> → <code>abc</code></td></tr><tr><td><strong><code>uppercase()</code></strong></td><td>Верхний регистр</td><td><code>abc</code> → <code>ABC</code></td></tr><tr><td><strong><code>replace(&quot;a&quot;,&quot;b&quot;)</code></strong></td><td>Заменить все вхождения подстроки <strong>a</strong> на <strong>b</strong></td><td><code>replace(&quot;-&quot;, &quot;&quot;)</code></td></tr><tr><td><strong><code>substring(start,end)</code></strong></td><td>Срез как в <strong><code>String.prototype.slice(start, end)</code></strong></td><td><code>substring(0, 8)</code></td></tr><tr><td><strong><code>removeNonDigits()</code></strong></td><td>Оставить только цифры</td><td><code>+54 (11) 5555</code> → <code>54115555</code></td></tr><tr><td><strong><code>prefix(&quot;x&quot;)</code></strong></td><td>Префикс</td><td><code>prefix(&quot;id-&quot;)</code></td></tr><tr><td><strong><code>suffix(&quot;x&quot;)</code></strong></td><td>Суффикс</td><td><code>suffix(&quot;-prod&quot;)</code></td></tr></tbody></table><p>Аргументы в <strong><code>replace</code></strong>, <strong><code>prefix</code></strong>, <strong><code>suffix</code></strong> задаются в <strong>двойных</strong> или <strong>одинарных</strong> кавычках. Внутри строки символ <strong><code>\\\\</code></strong> экранирует следующий символ.</p><p>Неизвестное имя «функции» или ошибка в числе аргументов для <strong>substring</strong> / <strong>replace</strong> приводит к тому, что <strong>этот шаг пропускается</strong> (значение на входе следующего шага не меняется из-за этого шага).</p><h3 id="плеисхолдер-и-подсказка" tabindex="-1">Плейсхолдер и подсказка <a class="header-anchor" href="#плеисхолдер-и-подсказка" aria-label="Permalink to &quot;Плейсхолдер и подсказка&quot;">​</a></h3><p>Типовой пример цепочки в поле ввода:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replace(&quot;-&quot;, &quot;&quot;) | lowercase()</span></span></code></pre></div><p>Короткие примеры для ориентации: <strong><code>trim()</code></strong>, <strong><code>lowercase()</code></strong>, <strong><code>replace(&quot;-&quot;, &quot;&quot;)</code></strong>.</p><hr><h2 id="сквозные-примеры" tabindex="-1">Сквозные примеры <a class="header-anchor" href="#сквозные-примеры" aria-label="Permalink to &quot;Сквозные примеры&quot;">​</a></h2><h3 id="нормализация-uuid" tabindex="-1">Нормализация UUID <a class="header-anchor" href="#нормализация-uuid" aria-label="Permalink to &quot;Нормализация UUID&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">([a-f0-9-]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">{36}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replace(&quot;-&quot;, &quot;&quot;)</span></span></code></pre></div><p><strong>Результат для подстановки в <code>{value}</code>:</strong> шестнадцатеричная строка без дефисов, например <code>fbdb0effcaf44d4d86652a71f5556274</code>.</p><h3 id="извлечь-числовои-идентификатор" tabindex="-1">Извлечь числовой идентификатор <a class="header-anchor" href="#извлечь-числовои-идентификатор" aria-label="Permalink to &quot;Извлечь числовой идентификатор&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trim()</span></span></code></pre></div><h3 id="весь-заголовок-в-нижнии-регистр" tabindex="-1">Весь заголовок в нижний регистр <a class="header-anchor" href="#весь-заголовок-в-нижнии-регистр" aria-label="Permalink to &quot;Весь заголовок в нижний регистр&quot;">​</a></h3><p><strong>Extract regex:</strong></p><div class="language-regex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">regex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre></div><p><strong>Transform:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trim() | lowercase()</span></span></code></pre></div><hr><h2 id="краткая-памятка" tabindex="-1">Краткая памятка <a class="header-anchor" href="#краткая-памятка" aria-label="Permalink to &quot;Краткая памятка&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> расширяет заголовки за счёт <strong><code>webRequest</code></strong>; <strong>Standalone</strong> этого режима не предоставляет.</li><li><strong>Classic mode</strong> — прежняя модель «видимости» заголовков для страницы.</li><li><strong>Pin</strong> — отдельно для списков <strong>Request</strong> / <strong>Response</strong>.</li><li><strong>Header links:</strong> шаблон с <strong><code>{value}</code></strong>, опционально <strong>Extract regex</strong>, затем <strong>Transform</strong> (цепочка через <code>|</code>).</li></ul>',55)])])}const u=s(r,[["render",n]]);export{h as __pageData,u as default};
